parameters.jsonBody:
={{ JSON.stringify({
  contents: [{ parts: [{ text:
    "From the Texas Comptroller markdown tables below, extract every data-center facility listed. For EACH, infer its Texas CITY and COUNTY from the data-center name and the owner/operator company name. Examples: 'LinkedIn Richardson' is in Richardson (Dallas County); 'COPT San Antonio LP' is in San Antonio (Bexar County); 'Giga Texas' (Tesla) is in Austin (Travis County). If you cannot determine a Texas county with reasonable confidence, set county to an empty string. Return STRICT JSON: an array of objects with keys: company (the data-center or owner name), city (Texas city or empty), county (Texas county WITHOUT the word 'County', or empty if unknown), status (one of: operating, under-construction, proposed; use 'operating' unless the table marks it a planned or large project). Do not invent facilities that are not in the tables. Return [] if none.\n\nMARKDOWN:\n" + $json.data.markdown
  }]}],
  generationConfig: { temperature: 0, responseMimeType: "application/json" }
}) }}

parameters.jsCode:
const resp = $json;
let text = '';
try { text = resp.candidates[0].content.parts[0].text || ''; } catch (e) { text = ''; }
text = text.trim().replace(/^```(json)?/i, '').replace(/```$/,'').trim();
let arr = [];
try { arr = JSON.parse(text); } catch (e) {
  const m = text.match(/\[([\s\S]*)\]/);
  if (m) { try { arr = JSON.parse(m[0]); } catch (e2) { arr = []; } }
}
if (!Array.isArray(arr)) arr = [];
const candidates = arr
  .filter(c => c && c.company)
  .map(c => ({
    company: String(c.company).trim(),
    city: String(c.city || '').trim(),
    county: String(c.county || '').replace(/county/ig, '').trim(),
    status: String(c.status || 'operating').trim().toLowerCase()
  }));
return [{ json: { candidates } }];

// Build ONE git-tree of all placeable, NEW, deduped facility files for a single batch PR.
const slugify = s => String(s).toLowerCase().normalize('NFKD').replace(/[^a-z0-9]+/g,'-').replace(/(^-|-$)/g,'');
const candidates = $('Parse candidates').first().json.candidates || [];
let _c = $('Get county centroids').first().json;
if (typeof _c === 'string') { try { _c = JSON.parse(_c); } catch (e) { _c = {}; } }
if (_c && typeof _c.data === 'string') { try { _c = JSON.parse(_c.data); } catch (e) {} }
const centroids = (_c && _c.counties) ? _c.counties : {};
const existingItems = $('Get existing facilities').all();
const existingSlugs = new Set(
  existingItems.flatMap(it => Array.isArray(it.json) ? it.json : [it.json])
    .map(f => (f && f.name ? String(f.name).replace(/\.json$/,'') : ''))
    .filter(Boolean)
);
const ALLOWED = ['proposed','permitted','under-construction','operating'];
const today = new Date().toISOString().slice(0,10);
const seen = new Set();
const tree = [];
const placed = [];
const skipped = [];
for (const c of candidates) {
  if (!c.company || !c.county) { skipped.push((c.company || '?') + ' (no county inferred)'); continue; }
  const coords = centroids[c.county.toLowerCase().trim()];
  if (!coords) { skipped.push(c.company + ' / ' + c.county + ' (county not in centroid lookup)'); continue; }
  const slug = slugify(c.company + '-' + c.county + '-data-center');
  if (existingSlugs.has(slug) || seen.has(slug)) continue;
  seen.add(slug);
  const facility = {
    name: c.company + ' Data Center',
    operator: c.company,
    county: c.county,
    status: ALLOWED.includes(c.status) ? c.status : 'operating',
    sourceUrl: 'https://comptroller.texas.gov/taxes/data-centers/data-center-lists.php',
    sourceName: 'Texas Comptroller \u2014 qualifying data center registry',
    note: ('Registered as a qualifying data center with the Texas Comptroller, in ' + c.county + ' County.' + (c.city ? ' Listed near ' + c.city + '.' : '') + ' (Our summary; see source.)'),
    dateFound: today,
    lat: coords[0],
    lng: coords[1]
  };
  if (c.city) facility.city = c.city;
  tree.push({ path: 'src/content/facilities/' + slug + '.json', mode: '100644', type: 'blob', content: JSON.stringify(facility, null, 2) + '\n' });
  placed.push(facility.name + ' (' + c.county + ')');
}
const branch = 'facility-backfill-comptroller-' + today;
return [{ json: { tree, placed, placedCount: placed.length, skipped, skippedCount: skipped.length, branch } }];

parameters.jsonBody:
